import{_ as e,o as n,c as a,ae as r}from"./chunks/framework.Czhw_PXq.js";const x=JSON.parse('{"title":"OpenSIN-AI Agent: Feature Comparison & Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"guide/opensin-ai-agent-features.md","filePath":"guide/opensin-ai-agent-features.md"}'),l={name:"guide/opensin-ai-agent-features.md"};function i(d,t,s,o,c,g){return n(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="opensin-ai-agent-feature-comparison-roadmap" tabindex="-1">OpenSIN-AI Agent: Feature Comparison &amp; Roadmap <a class="header-anchor" href="#opensin-ai-agent-feature-comparison-roadmap" aria-label="Permalink to &quot;OpenSIN-AI Agent: Feature Comparison &amp; Roadmap&quot;">​</a></h1><blockquote><p>How OpenSIN-AI Agent compares against OpenClaw, Google Gemini Agent, and Claude Code — and our plan to surpass them all.</p></blockquote><hr><h2 id="feature-comparison-matrix" tabindex="-1">Feature Comparison Matrix <a class="header-anchor" href="#feature-comparison-matrix" aria-label="Permalink to &quot;Feature Comparison Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th style="text-align:center;">OpenSIN-AI</th><th style="text-align:center;">OpenClaw</th><th style="text-align:center;">Gemini Agent</th><th style="text-align:center;">Claude Code</th></tr></thead><tbody><tr><td><strong>Core</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Open Source</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>Self-Hosted</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>24/7 Autonomous</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅ (3 days)</td></tr><tr><td>Multi-Model</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td><strong>Intelligence</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Heartbeat/Cron</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅ (limited)</td><td style="text-align:center;">✅ (/loop)</td></tr><tr><td>Persistent Memory</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td>Structured Wiki</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>Session Branching</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td><strong>Communication</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Telegram</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td>WhatsApp</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>Discord</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td>Signal</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>iMessage</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>Slack</td><td style="text-align:center;">🔲</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>MS Teams</td><td style="text-align:center;">🔲</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td><strong>Automation</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Subagent Spawning</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td>External Harness (ACP)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>Webhook Triggers</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>Unified Agent Orchestrator</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>Browser Automation</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><strong>Workspace</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Google Workspace</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr><tr><td>Apple Ecosystem</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>Microsoft 365</td><td style="text-align:center;">🔲</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td><strong>SDK &amp; Dev</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Agent SDK</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td>Plugin System</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>MCP Support</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td></tr><tr><td><strong>Safety</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Approval Hooks</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>Audit Logging</td><td style="text-align:center;">🔲</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>Risk Classification</td><td style="text-align:center;">🔲</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td><strong>Advanced</strong></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td></tr><tr><td>Voice Wake</td><td style="text-align:center;">✅ (Siri)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr><tr><td>Canvas/A2UI</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td></tr><tr><td>Computer Use</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr></tbody></table><p><strong>Legend:</strong> ✅ Implemented | 🔲 Planned | ❌ Not available</p><hr><h2 id="opensin-ai-unique-advantages" tabindex="-1">OpenSIN-AI Unique Advantages <a class="header-anchor" href="#opensin-ai-unique-advantages" aria-label="Permalink to &quot;OpenSIN-AI Unique Advantages&quot;">​</a></h2><h3 id="_1-a2a-fleet-architecture-92-workers" tabindex="-1">1. A2A Fleet Architecture (92+ Workers) <a class="header-anchor" href="#_1-a2a-fleet-architecture-92-workers" aria-label="Permalink to &quot;1. A2A Fleet Architecture (92+ Workers)&quot;">​</a></h3><p>Unlike competitors that run as a single process, OpenSIN-AI has <strong>92+ specialized agents</strong> — each with its own CLI, MCP server, and A2A endpoint. This means:</p><ul><li><strong>Specialization beats generalization</strong> — each agent is an expert in its domain</li><li><strong>Horizontal scaling</strong> — add more agents without changing the core</li><li><strong>Fault isolation</strong> — one agent crash doesn&#39;t take down the system</li></ul><h3 id="_2-n8n-foundation-free-indestructible" tabindex="-1">2. n8n Foundation (Free, Indestructible) <a class="header-anchor" href="#_2-n8n-foundation-free-indestructible" aria-label="Permalink to &quot;2. n8n Foundation (Free, Indestructible)&quot;">​</a></h3><p>OpenSIN-AI uses n8n on a free OCI VM as its routing backbone:</p><ul><li><strong>Zero cost</strong> — Oracle Cloud Always-Free tier</li><li><strong>Visual workflows</strong> — drag-and-drop automation</li><li><strong>200+ integrations</strong> — n8n&#39;s built-in connector library</li><li><strong>No vendor lock-in</strong> — self-hosted, full control</li></ul><h3 id="_3-apple-ecosystem-native-12-agents" tabindex="-1">3. Apple Ecosystem Native (12 Agents) <a class="header-anchor" href="#_3-apple-ecosystem-native-12-agents" aria-label="Permalink to &quot;3. Apple Ecosystem Native (12 Agents)&quot;">​</a></h3><p>No competitor has native Apple automation:</p><ul><li>FaceTime, iMessage, Notes, Calendar, Reminders, Safari, Shortcuts</li><li>macOS system control (AppleScript, System Events)</li><li>iPhone integration (USB, screenshots, shortcuts)</li><li>Siri voice commands via Shortcuts</li></ul><h3 id="_4-triple-trigger-system" tabindex="-1">4. Triple Trigger System <a class="header-anchor" href="#_4-triple-trigger-system" aria-label="Permalink to &quot;4. Triple Trigger System&quot;">​</a></h3><p>OpenSIN-AI supports three independent trigger mechanisms:</p><ol><li><strong>Heartbeat</strong> — Periodic agent check-in (like OpenClaw)</li><li><strong>Cron Scheduler</strong> — Scheduled recurring tasks (like Gemini)</li><li><strong>Webhook</strong> — External event triggers (like OpenClaw)</li></ol><h3 id="_5-multi-model-freedom" tabindex="-1">5. Multi-Model Freedom <a class="header-anchor" href="#_5-multi-model-freedom" aria-label="Permalink to &quot;5. Multi-Model Freedom&quot;">​</a></h3><p>Unlike Claude Code (Claude only) or Gemini Agent (Gemini only):</p><ul><li>OpenAI GPT-5.4 (primary, via Antigravity)</li><li>Google Gemini 3.1 Pro/Flash (via Antigravity)</li><li>Anthropic Claude Sonnet/Opus (via Antigravity)</li><li>NVIDIA Qwen 3.5 (via NIM)</li><li>Any local model (via Ollama)</li></ul><hr><h2 id="implementation-roadmap" tabindex="-1">Implementation Roadmap <a class="header-anchor" href="#implementation-roadmap" aria-label="Permalink to &quot;Implementation Roadmap&quot;">​</a></h2><h3 id="phase-1-foundation-sprint-1-2" tabindex="-1">Phase 1: Foundation (Sprint 1-2) <a class="header-anchor" href="#phase-1-foundation-sprint-1-2" aria-label="Permalink to &quot;Phase 1: Foundation (Sprint 1-2)&quot;">​</a></h3><ul><li>Heartbeat system in <code>opensin-ai-cli</code></li><li>Multi-model router with failover</li><li>Cron scheduler and unified agent orchestrator</li><li>Approval hooks and permission gate integration</li><li>Unified messaging API</li><li>Extended memory system</li></ul><h3 id="phase-2-reach-control-sprint-3-4" tabindex="-1">Phase 2: Reach &amp; Control (Sprint 3-4) <a class="header-anchor" href="#phase-2-reach-control-sprint-3-4" aria-label="Permalink to &quot;Phase 2: Reach &amp; Control (Sprint 3-4)&quot;">​</a></h3><ul><li>Channel-based remote control</li><li>Generic subagent spawning</li><li>Progress tracking</li><li>Approval hooks framework</li></ul><h3 id="phase-3-orchestration-sprint-5-6" tabindex="-1">Phase 3: Orchestration (Sprint 5-6) <a class="header-anchor" href="#phase-3-orchestration-sprint-5-6" aria-label="Permalink to &quot;Phase 3: Orchestration (Sprint 5-6)&quot;">​</a></h3><ul><li>External harness control (ACP)</li><li>Session branching &amp; compaction</li><li>Audit logging</li></ul><h3 id="phase-4-differentiation-sprint-7-8" tabindex="-1">Phase 4: Differentiation (Sprint 7-8) <a class="header-anchor" href="#phase-4-differentiation-sprint-7-8" aria-label="Permalink to &quot;Phase 4: Differentiation (Sprint 7-8)&quot;">​</a></h3><ul><li>Canvas/A2UI workspace</li><li>Voice interaction</li><li>Extended Google Workspace (Gmail, Calendar, Slides)</li></ul><hr><h2 id="sprint-1-verified" tabindex="-1">Sprint 1 Verified <a class="header-anchor" href="#sprint-1-verified" aria-label="Permalink to &quot;Sprint 1 Verified&quot;">​</a></h2><ul><li><code>HeartbeatSystem</code> now handles autonomous check-ins, queue polling, backoff, and graceful shutdown.</li><li><code>FailoverRouter</code> now selects across OpenAI OCI, Antigravity, and NIM with health-based fallback.</li><li><code>CronScheduler</code> now parses cron expressions and executes scheduled tasks.</li><li><code>ApprovalHooks</code> now enforces risk-based gating for safe, write, destructive, network, financial, and auth actions.</li><li><code>AgentOrchestrator</code> ties the systems together with <code>AgentLoop</code>, <code>LoopMode</code>, <code>SmartModelRouter</code>, and <code>PermissionEvaluator</code>.</li><li><code>CLIAgent</code> now routes through the orchestrator for model selection and approval policy checks.</li></ul><hr><p><em>See also: <a href="https://github.com/OpenSIN-AI/OpenSIN-overview/blob/main/docs/opensin-ai-agent-feature-spec.md" target="_blank" rel="noreferrer">OpenSIN-AI Agent Feature Spec</a></em></p>',38)])])}const p=e(l,[["render",i]]);export{x as __pageData,p as default};
